svg.script:

(function () {
  const svg = document.documentElement;

  const audio = new Audio(
    "data:audio/ogg;base64,",
  );
  audio.preload = "auto";

  function playSound() {
    audio.currentTime = 0;
    audio
      .play()
      .catch((e) => console.warn("Audio play blocked by browser:", e));
  }

  svg.addEventListener("pointerdown", playSound);

  // --- KEYBOARD ACCESSIBILITY ONLY ---
  svg.addEventListener("keydown", (e) => {
    if (e.key === " " || e.key === "Enter") {
      e.preventDefault(); // Prevents page scroll on Space
      if (!svg.classList.contains("pressed")) {
        svg.classList.add("pressed");
        playSound();
      }
    }
  });

  svg.addEventListener("keyup", (e) => {
    if (e.key === " " || e.key === "Enter") {
      svg.classList.remove("pressed");
    }
  });

  svg.addEventListener("blur", () => svg.classList.remove("pressed"));
})();
